VALUES
  ('elementary-0489de64-moex-00151', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '公路法第34條，公路汽車運輸，分自用與營業兩種。營業汽車應依規定分類營運，下列營業汽車營 運範圍之描述何者錯誤？', '["汽車貨運業：在核定路線內，以載貨小貨車或小客貨兩用車運送貨物為營業者", "公路汽車客運業：在核定路線內，以公共汽車運輸旅客為營業者", "遊覽車客運業：在核定區域內，以遊覽車包租載客為營業者", "小貨車租賃業：以小貨車或小客貨兩用車租與他人自行使用為營業者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00152', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '日前社會也關切高鐵、臺鐵、客運及捷運票價之調漲問題，請選出運輸業者要能永續經營其定價時必 須考量的因素：', '["能獲利的生產成本", "爭取獨占的市場結構", "創造價格彈性趨近於零的民眾需求特性", "提高競爭的低價訂價策略"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00153', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '公路法第34條，營業汽車分：①公路汽車客運業  ②巿區汽車客運業  ③遊覽車客運業  ④計程車 客運業  ⑤小客車租賃業  ⑥小貨車租賃業  ⑦汽車貨運業  ⑧汽車路線貨運業  ⑨汽車貨櫃貨運 業等九業，請選出下列需在區域內營運者：', '["", "", "", "⑤"]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00154', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '鐵路法中第3條，鐵路以國營為原則，地方營、民營及專用鐵路之興建、延長或經營等，請問近日研 議高鐵延伸屏東或宜蘭等站應經下列何者核准？', '["行政院", "國家發展委員會", "交通部", "交通部鐵道局"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00155', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '國營臺灣鐵路股份有限公司於113年9月10日召開董事會，討論票價調整事宜。若要調漲運價，按 鐵路法中第26條國營鐵路運價率之計算公式計算後，由何者審定之？', '["國營臺灣鐵路股份有限公司董事會", "立法院", "交通部", "行政院"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00156', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '現代運輸系統提供的服務至少應達①安全  ②迅速  ③準點  ④便利  ⑤舒適  ⑥經濟  ⑦永續等 目標，請選出首要目標者：', '["準點", "安全", "經濟", "永續"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00157', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '交通部考量計程車輛自領牌後始得實際投入使用，故將排班計程車車齡限制加以修改，於113年10 月修正「民用航空機場客運汽車管理辦法」第13、28條等之部分規定，請選出正確者：', '["自汽車出廠後首次領牌日之次日起算", "自汽車出廠後首次領牌日之次月1日起算，在4年以內", "自汽車出廠後次日起算", "自汽車出廠後次月1日起算"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00158', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '貨櫃運輸最大的優點之一為使用標準化的貨櫃便於機械化裝運，請選出最大載重28公噸以上的貨櫃 尺寸：', '["20呎冷凍櫃", "40呎冷凍櫃", "45呎超高普通櫃", "40呎超高普通櫃"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00159', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '依據「民用航空法」定義「普通航空業：包括空中遊覽、勘察、照測、消防、搜尋、救護、拖吊、噴 灑、拖靶勤務、商務專機及其他經核准之飛航業務。」，何者屬未來空中計程車之飛航業務範圍？', '["商業式飛行", "個人飛行", "教練飛行", "其他飛行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00160', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '交通部民用航空局修改「民用航空法」遙控無人機專章（第9章之2），請問下列描述從事遙控無人 機飛航活動應遵守之規定何者錯誤？', '["不得於日落後至日出前之時間飛航", "不得於人群聚集或室外集會遊行上空活動", "在目視範圍內操作，不得以除矯正鏡片外之任何工具延伸飛航作業距離", "遙控無人機飛航活動之實際高度，不得逾距地面或水面800呎"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL)
